#include <iostream>
#include <sstream>
#include <string>
#include <vector>

void printFibonacci(int n);

int main() {
    std::vector<int> test_inputs = {0, 1, 5, 10, -5, 47};
    for (size_t i = 0; i < test_inputs.size(); ++i) {
        std::stringstream ss;
        std::streambuf* old_cout = std::cout.rdbuf();
        std::cout.rdbuf(ss.rdbuf());
        printFibonacci(test_inputs[i]);
        std::cout.rdbuf(old_cout);
    }
    return 0;
}
